text:
if (cmd->data.draw.texture) {
    const GSPRIMUVPOINT *verts = (GSPRIMUVPOINT *) ((Uint8*)vertices + cmd->data.draw.first);
    GSTEXTURE *ps2_tex = (GSTEXTURE *)cmd->data.draw.texture->internal;

    switch (cmd->data.draw.texture_scale_mode) {
    case SDL_SCALEMODE_PIXELART:
    case SDL_SCALEMODE_NEAREST:
        ps2_tex->Filter = GS_FILTER_NEAREST;
        break;
    case SDL_SCALEMODE_LINEAR:
        ps2_tex->Filter = GS_FILTER_LINEAR;
        break;
    default:
        break;
    }
    gsKit_TexManager_bind(data->gsGlobal, ps2_tex);
    gsKit_prim_list_triangle_goraud_texture_uv_3d(data->gsGlobal, ps2_tex, count, verts);
} else {
    const GSPRIMPOINT *verts = (GSPRIMPOINT *)((Uint8*)vertices + cmd->data.draw.first);
    gsKit_prim_list_triangle_gouraud_3d(data->gsGlobal, count, verts);
}

for (int i = 0; i < count; i++, rects++) {
    verts[i * 2].x = Real2Fix(rects->x);
    verts[i * 2].y = Real2Fix(rects->y);
    verts[i * 2 + 1].x = Real2Fix(rects->w);
    verts[i * 2 + 1].y = Real2Fix(rects->h);

    verts[i * 2].x = Fix2Int(verts[i * 2].x);
    verts[i * 2].y = Fix2Int(verts[i * 2].y);
    verts[i * 2 + 1].x = Fix2Int(verts[i * 2 + 1].x);
    verts[i * 2 + 1].y = Fix2Int(verts[i * 2 + 1].y);

    Uint32 color = NGAGE_ConvertColor(cmd->data.draw.color.r, cmd->data.draw.color.g, cmd->data.draw.color.b, cmd->data.draw.color.a, cmd->data.draw.color_scale);

    verts[i * 2].color.a = (Uint8)(color >> 24);
    verts[i * 2].color.b = (Uint8)(color >> 16);
    verts[i * 2].color.g = (Uint8)(color >> 8);
    verts[i * 2].color.r = (Uint8)color;
}

if (sc != SDL_SCANCODE_UNKNOWN) {
    SDL_SendKeyboardKey(0, SDL_GLOBAL_KEYBOARD_ID, 0, sc, pressed);

    // Generate text input events for key-down on printable characters.
    // SDL keycodes below SDLK_SCANCODE_MASK are Unicode codepoints.
    if (pressed) {
        SDL_Keymod mod = SDL_GetModState();
        if (!(mod & (SDL_KMOD_CTRL | SDL_KMOD_ALT))) {
            SDL_Keycode keycode = SDL_GetKeyFromScancode(sc, mod, false);
            if (keycode > 0 && keycode < SDLK_SCANCODE_MASK && !SDL_iscntrl((int)keycode)) {
                char text[5];
                char *end = SDL_UCS4ToUTF8((Uint32)keycode, text);
                *end = '\0';
                SDL_SendKeyboardText(text);
            }
        }
    }
}

if (r->headers_out.content_type.len) {
    ctx->boundary_header.len = ngx_sprintf(ctx->boundary_header.data,
                                       CRLF "--%0muA" CRLF
                                       "Content-Type: %V" CRLF
                                       "Content-Range: bytes ",
                                       boundary,
                                       &r->headers_out.content_type)
                               - ctx->boundary_header.data;

} else {
    ctx->boundary_header.len = ngx_sprintf(ctx->boundary_header.data,
                                       CRLF "--%0muA" CRLF
                                       "Content-Range: bytes ",
                                       boundary)
                               - ctx->boundary_header.data;
}

if (r->headers_out.server == NULL) {
    if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_ON) {
        p = (u_char *) NGINX_VER;
        n = sizeof(NGINX_VER) - 1;

    } else if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_BUILD) {
        p = (u_char *) NGINX_VER_BUILD;
        n = sizeof(NGINX_VER_BUILD) - 1;

    } else {
        p = (u_char *) "nginx";
        n = sizeof("nginx") - 1;
    }

    ngx_log_debug2(NGX_LOG_DEBUG_HTTP, c->log, 0,
                   "http3 output header: \"server: %*s\"", n, p);

    b->last = (u_char *) ngx_http_v3_encode_field_lri(b->last, 0,
                                                 NGX_HTTP_V3_HEADER_SERVER,
                                                 p, n);
}

if (mtx->semaphore) {
    (void) ngx_atomic_fetch_add(mtx->wait, 1);

    if (*mtx->lock == 0 && ngx_atomic_cmp_set(mtx->lock, 0, ngx_pid)) {
        (void) ngx_atomic_fetch_add(mtx->wait, -1);
        return;
    }

    ngx_log_debug1(NGX_LOG_DEBUG_CORE, ngx_cycle->log, 0,
                   "shmtx wait %uA", *mtx->wait);

    while (sem_wait(&mtx->sem) == -1) {
        ngx_err_t  err;

        err = ngx_errno;

        if (err != NGX_EINTR) {
            ngx_log_error(NGX_LOG_ALERT, ngx_cycle->log, err,
                          "sem_wait() failed while waiting on shmtx");
            break;
        }
    }

    ngx_log_debug0(NGX_LOG_DEBUG_CORE, ngx_cycle->log, 0,
                   "shmtx awoke");

    continue;
}

if (pctx->operation == EVP_PKEY_OP_SIGNCTX
        && pctx->op.sig.algctx != NULL
        && pctx->op.sig.signature != NULL) {
        EVP_SIGNATURE *signature = pctx->op.sig.signature;

        if (signature->digest_sign != NULL) {
            const char *desc = signature->description != NULL ? signature->description : "";

            if (sigret != NULL)
                ctx->flags |= EVP_MD_CTX_FLAG_FINALISED;
            ERR_set_mark();
            ret = signature->digest_sign(pctx->op.sig.algctx, sigret, siglen,
                sigret == NULL ? 0 : *siglen, tbs, tbslen);
            if (ret <= 0 && ERR_count_to_mark() == 0)
                ERR_raise_data(ERR_LIB_EVP, EVP_R_PROVIDER_SIGNATURE_FAILURE,
                    "%s digest_sign:%s", signature->type_name, desc);
            ERR_clear_last_mark();
            return ret;
        }
    }

if (tmpl != NULL || param_p != NULL || param_a != NULL || param_b != NULL) {
    BIGNUM *p = BN_CTX_get(bnctx);
    BIGNUM *a = BN_CTX_get(bnctx);
    BIGNUM *b = BN_CTX_get(bnctx);

    if (b == NULL) {
        ERR_raise(ERR_LIB_EC, ERR_R_BN_LIB);
        goto err;
    }

    if (!EC_GROUP_get_curve(group, p, a, b, bnctx)) {
        ERR_raise(ERR_LIB_EC, EC_R_INVALID_CURVE);
        goto err;
    }
    if (!ossl_param_build_set_bn(tmpl, params, OSSL_PKEY_PARAM_EC_P, p)
        || !ossl_param_build_set_bn(tmpl, params, OSSL_PKEY_PARAM_EC_A, a)
        || !ossl_param_build_set_bn(tmpl, params, OSSL_PKEY_PARAM_EC_B, b)) {
        ERR_raise(ERR_LIB_EC, ERR_R_CRYPTO_LIB);
        goto err;
    }
}

if (EVP_CIPHER_get_mode(ciph) == EVP_CIPH_CCM_MODE) {
    if (!EVP_CipherInit_ex(ciph_ctx, ciph, NULL, NULL, NULL, enc)
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_AEAD_SET_IVLEN, 12,
               NULL)
            <= 0
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_AEAD_SET_TAG,
               (int)taglen, NULL)
            <= 0
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_CCM_SET_IV_FIXED,
               (int)ivlen, iv)
            <= 0
        || !EVP_CipherInit_ex(ciph_ctx, NULL, NULL, key, NULL, enc)) {
        ERR_raise(ERR_LIB_SSL, ERR_R_INTERNAL_ERROR);
        return OSSL_RECORD_RETURN_FATAL;
    }
} else {
    if (!EVP_CipherInit_ex(ciph_ctx, ciph, NULL, key, iv, enc)) {
        ERR_raise(ERR_LIB_SSL, ERR_R_INTERNAL_ERROR);
        return OSSL_RECORD_RETURN_FATAL;
    }
}

if (len > pool->alloc_len - pool->len) {
    unsigned char *p;
    const size_t limit = pool->max_len / 2;
    size_t newlen = pool->alloc_len;

    if (pool->attached || len > pool->max_len - pool->len) {
        ERR_raise(ERR_LIB_RAND, ERR_R_INTERNAL_ERROR);
        return 0;
    }

    do
        newlen = newlen < limit ? newlen * 2 : pool->max_len;
    while (len > newlen - pool->len);

    if (pool->secure)
        p = OPENSSL_secure_zalloc(newlen);
    else
        p = OPENSSL_zalloc(newlen);
    if (p == NULL)
        return 0;
    memcpy(p, pool->buffer, pool->len);
    if (pool->secure)
        OPENSSL_secure_clear_free(pool->buffer, pool->alloc_len);
    else
        OPENSSL_clear_free(pool->buffer, pool->alloc_len);
    pool->buffer = p;
    pool->alloc_len = newlen;
}

switch (cmd) {
case X509_L_FILE_LOAD:
    if (argl == X509_FILETYPE_DEFAULT) {
        file = ossl_safe_getenv(X509_get_default_cert_file_env());
        if (file)
            ok = (X509_load_cert_crl_file_ex(ctx, file, X509_FILETYPE_PEM,
                      libctx, propq)
                != 0);
        else
            ok = (X509_load_cert_crl_file_ex(
                      ctx, X509_get_default_cert_file(),
                      X509_FILETYPE_PEM, libctx, propq)
                != 0);

        if (!ok)
            ERR_raise(ERR_LIB_X509, X509_R_LOADING_DEFAULTS);
    } else {
        if (argl == X509_FILETYPE_PEM)
            ok = (X509_load_cert_crl_file_ex(ctx, argp, X509_FILETYPE_PEM,
                      libctx, propq)
                != 0);
        else
            ok = (X509_load_cert_file_ex(ctx, argp, (int)argl, libctx,
                      propq)
                != 0);
    }
    break;
}

if (tok->encoding == NULL) {
    assert(tok->decoding_readline == NULL);
    if (strcmp(cs, "utf-8") != 0 && !set_readline(tok, cs)) {
        _PyTokenizer_error_ret(tok);
        PyErr_Format(PyExc_SyntaxError, "encoding problem: %s", cs);
        PyMem_Free(cs);
        return 0;
    }
    tok->encoding = cs;
} else {                /* then, compare cs with BOM */
    if (strcmp(tok->encoding, cs) != 0) {
        tok->line_start = line;
        tok->cur = (char *)line;
        assert(size <= INT_MAX);
        _PyTokenizer_syntaxerror_known_range(tok, 0, (int)size,
                    "encoding problem: %s with BOM", cs);
        PyMem_Free(cs);
        _PyTokenizer_error_ret(tok);
        return 0;
    }
    PyMem_Free(cs);
}
